// Optimized for Polygon PoS & zkEVM data location usage
contract EfficientStorage {
    // Pack two uint128s into a single 32-byte storage slot (one SSTORE)
    struct Slot { uint128 a; uint128 b; }
    mapping(address => Slot) public data;

    // calldata: 16 gas/non-zero byte — never copied to memory
    function processInput(bytes calldata payload) external pure returns (bytes32) {
        return keccak256(payload);
    }

    // unchecked saves ~200 gas/iter on Polygon PoS (still ~$0.0001)
    function sumCalldata(uint256[] calldata nums) external pure returns (uint256 total) {
        for (uint256 i; i < nums.length; ) {
            total += nums[i];
            unchecked { ++i; }
        }
    }
}

