import { createPublicClient, http } from "viem";
import { polygon } from "viem/chains";

const client = createPublicClient({ chain: polygon, transport: http() });

async function getTxFinality(txHash: `0x${string}`) {
  const receipt = await client.getTransactionReceipt({ hash: txHash });
  if (!receipt) return { status: "pending" };

  const latestBlock = await client.getBlockNumber();
  const confirmations = latestBlock - receipt.blockNumber;

  // ~256 Bor blocks ≈ one Heimdall checkpoint anchored on Ethereum L1
  if (confirmations >= 256n) return { status: "checkpoint-safe", confirmations };
  if (confirmations >= 128n) return { status: "soft-final", confirmations };
  return { status: "confirming", confirmations };
}

